/**
 * Milestone-1 parity anchor for the Janino codegen plan (plans/lmdb-native-engine/17-janino-whole-stage-codegen.md):
 * proves the hand-written ceiling kernels ({@link JaninoCeilingKernels}) produce exactly the generic evaluator's
 * results on a FOAF-clique store, so the ceiling benchmark measures correct code. Query shapes: cycle3GroupedInterest,
 * cycle4, and the ANALYTICS predicate-selectivity profile (dataset-independent shape, exercised here on FOAF data).
 */
@TestInstance(TestInstance.Lifecycle.PER_CLASS)
public class JaninoCeilingParityTest {

	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String PREFIXES = "PREFIX foaf: <http://xmlns.com/foaf/0.1/>\n"
			+ "PREFIX exinterest: <http://example.org/foaf/meta/interest/>\n";

	private static final String CYCLE3_GROUPED_INTEREST = PREFIXES
			+ "SELECT ?interest (COUNT(DISTINCT ?a) AS ?memberCount) WHERE {\n"
			+ "  VALUES ?interest { exinterest:rdf exinterest:sparql exinterest:knowledgeGraphs }\n"
			+ "  ?a foaf:knows ?b .\n"
			+ "  ?b foaf:knows ?c .\n"
			+ "  ?c foaf:knows ?a .\n"
			+ "  FILTER (?a != ?b && ?a != ?c && ?b != ?c)\n"
			+ "  ?a foaf:interest ?interest .\n"
			+ "}\n"
			+ "GROUP BY ?interest\n"
			+ "HAVING (COUNT(DISTINCT ?a) >= 2)\n"
			+ "ORDER BY DESC(?memberCount) ?interest\n";

	private static final String CYCLE4 = PREFIXES
			+ "SELECT * WHERE {\n"
			+ "  ?a foaf:knows ?b .\n"
			+ "  ?b foaf:knows ?c .\n"
			+ "  ?c foaf:knows ?d .\n"
			+ "  ?d foaf:knows ?a .\n"
			+ "  FILTER (?a != ?b && ?a != ?c && ?a != ?d && ?b != ?c && ?b != ?d && ?c != ?d)\n"
			+ "}\n";

	private static final String PREDICATE_SELECTIVITY = "SELECT ?p (COUNT(*) AS ?statements) "
			+ "(COUNT(DISTINCT ?s) AS ?distinctSubjects) (COUNT(DISTINCT ?o) AS ?distinctObjects) WHERE {\n"
			+ "  ?s ?p ?o .\n"
			+ "}\n"
			+ "GROUP BY ?p\n"
			+ "ORDER BY DESC(?statements) ?p\n";

	private final ValueFactory vf = SimpleValueFactory.getInstance();
	private File dataDir;
	private SailRepository repository;
	private SailDataset dataset;
	private NativeLmdbQuerySource source;
	private NativeLmdbQuerySource.NativeProbe probe;
	private NativeLmdbQuerySource.NativeAdjacency knows;
	private NativeLmdbQuerySource.NativeAdjacency interestByObject;
	private long[] knowsSubjects;
	private long[] interestIds;
	private String previousNativeFlag;
	private String previousMinProbes;

	@BeforeAll
	public void setUp() throws Exception {
		previousNativeFlag = System.getProperty(NATIVE_FLAG);
		previousMinProbes = System.getProperty("rdf4j.lmdb.csrCache.minProbes");
		System.setProperty(NATIVE_FLAG, "false");
		System.setProperty("rdf4j.lmdb.csrCache.minProbes", "1");

		dataDir = Files.createTempDirectory("rdf4j-janino-ceiling-parity").toFile();
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc,posc");
		config.setForceSync(false);
		repository = new SailRepository(new LmdbStore(dataDir, config));
		repository.init();
		try (SailRepositoryConnection connection = repository.getConnection()) {
			new FoafCliqueDataGenerator(300, 30, 3, 6, 900, 12345).populate(connection);
		}

		LmdbStore store = (LmdbStore) repository.getSail();
		dataset = JaninoCeilingKernels.openDataset(store);
		source = (NativeLmdbQuerySource) dataset;
		probe = source.newProbe();

		long knowsId = source.idOf(vf.createIRI("http://xmlns.com/foaf/0.1/knows"));
		long interestPredId = source.idOf(vf.createIRI("http://xmlns.com/foaf/0.1/interest"));
		interestIds = new long[] {
				source.idOf(vf.createIRI("http://example.org/foaf/meta/interest/rdf")),
				source.idOf(vf.createIRI("http://example.org/foaf/meta/interest/sparql")),
				source.idOf(vf.createIRI("http://example.org/foaf/meta/interest/knowledgeGraphs")) };

		knowsSubjects = JaninoCeilingKernels.distinctSubjects(source, knowsId);
		knows = JaninoCeilingKernels.warmAdjacency(probe, knowsId, true, knowsSubjects);
		assertNotNull(knows, "CSR adjacency for foaf:knows BY_SUBJECT did not build");
		interestByObject = JaninoCeilingKernels.warmAdjacency(probe, interestPredId, false, interestIds);
		assertNotNull(interestByObject, "CSR adjacency for foaf:interest BY_OBJECT did not build");
	}

	@AfterAll
	public void tearDown() throws Exception {
		if (probe != null) {
			probe.close();
		}
		if (dataset != null) {
			dataset.close();
		}
		if (repository != null) {
			repository.shutDown();
		}
		if (dataDir != null) {
			FileUtils.deleteDirectory(dataDir);
		}
		restore(NATIVE_FLAG, previousNativeFlag);
		restore("rdf4j.lmdb.csrCache.minProbes", previousMinProbes);
	}

	private static void restore(String key, String previous) {
		if (previous == null) {
			System.clearProperty(key);
		} else {
			System.setProperty(key, previous);
		}
	}

	@Test
	public void cycle3GroupedInterestMatchesEngine() {
		List<String> engineRows = new ArrayList<>();
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult result = connection
						.prepareTupleQuery(QueryLanguage.SPARQL, CYCLE3_GROUPED_INTEREST)
						.evaluate()) {
			while (result.hasNext()) {
				BindingSet row = result.next();
				engineRows.add(row.getValue("interest").stringValue() + "|"
						+ ((Literal) row.getValue("memberCount")).longValue());
			}
		}

		long[] counts = JaninoCeilingKernels.cycle3GroupedInterestCounts(knows, interestByObject, interestIds);
		List<long[]> kept = new ArrayList<>();
		for (int i = 0; i < interestIds.length; i++) {
			if (counts[i] >= 2) {
				kept.add(new long[] { interestIds[i], counts[i] });
			}
		}
		kept.sort((x, y) -> {
			int byCount = Long.compare(y[1], x[1]);
			if (byCount != 0) {
				return byCount;
			}
			return source.lazyValue(x[0]).stringValue().compareTo(source.lazyValue(y[0]).stringValue());
		});
		List<String> kernelRows = new ArrayList<>();
		for (long[] row : kept) {
			kernelRows.add(source.lazyValue(row[0]).stringValue() + "|" + row[1]);
		}

		assertTrue(!engineRows.isEmpty(), "engine returned no rows; fixture too small to be meaningful");
		assertEquals(engineRows, kernelRows);
	}

	@Test
	public void cycle4CountMatchesEngine() {
		long engineCount;
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult result = connection.prepareTupleQuery(QueryLanguage.SPARQL, CYCLE4).evaluate()) {
			long count = 0;
			while (result.hasNext()) {
				result.next();
				count++;
			}
			engineCount = count;
		}
		long kernelCount = JaninoCeilingKernels.cycle4Count(knows, knowsSubjects);
		assertTrue(engineCount > 0, "engine returned no 4-cycles; fixture too small to be meaningful");
		assertEquals(engineCount, kernelCount);
	}

	@Test
	public void predicateSelectivityMatchesEngine() throws Exception {
		List<String> engineRows = new ArrayList<>();
		try (SailRepositoryConnection connection = repository.getConnection();
				TupleQueryResult result = connection
						.prepareTupleQuery(QueryLanguage.SPARQL, PREDICATE_SELECTIVITY)
						.evaluate()) {
			while (result.hasNext()) {
				BindingSet row = result.next();
				engineRows.add(((IRI) row.getValue("p")).stringValue() + "|"
						+ ((Literal) row.getValue("statements")).longValue() + "|"
						+ ((Literal) row.getValue("distinctSubjects")).longValue() + "|"
						+ ((Literal) row.getValue("distinctObjects")).longValue());
			}
		}

		long[][] rows = JaninoCeilingKernels.predicateSelectivity(source);
		List<String> kernelRows = JaninoCeilingKernels.formatPredicateSelectivity(rows, source);

		assertTrue(engineRows.size() > 5, "unexpectedly few predicates in fixture");
		assertEquals(engineRows, kernelRows);
	}
}
